svg.script:
const O=[{x:60,y:60},{x:-50,y:50},{x:35,y:-45},{x:-40,y:-35},{x:-35,y:40},{x:55,y:-50},{x:-55,y:-40}];
const F=[{x:24,y:14},{x:88,y:26},{x:34,y:60},{x:56,y:58},{x:78,y:52},{x:20,y:108},{x:100,y:100}];
const SD=900,SL=200,LS=7*SL+SD+200,LD=380,LL=120;
function ease(t){return t<.5?4*t*t*t:1-Math.pow(-2*t+2,3)/2;}
function easeOut(t){return 1-Math.pow(1-t,3);}
function anim({dur,delay:d=0,onP,onD}){
  const s=performance.now()+d;
  function f(n){const e=n-s;if(e<0){requestAnimationFrame(f);return;}
    const t=Math.min(1,e/dur);onP(t);
    if(t<1)requestAnimationFrame(f);else if(onD)onD();}
  requestAnimationFrame(f);}
function flash(el){anim({dur:550,onP(t){
  el.setAttribute('r',easeOut(t)*26);
  const op=t<.15?t/.15:1-(t-.15)/.85;el.setAttribute('opacity',op*.9);},
  onD(){el.setAttribute('opacity',0);}});}
function fadeIn(el,dur,delay){anim({dur,delay,onP(t){el.setAttribute('opacity',easeOut(t));}});}
F.forEach((f,i)=>{
  const el=document.getElementById('s'+i),fl=document.getElementById('f'+i),o=O[i];
  const cx=(o.x+f.x)/2+(f.y-o.y)*.35,cy=(o.y+f.y)/2+(o.x-f.x)*.35;
  anim({dur:SD,delay:i*SL,
    onP(t){
      const et=ease(t);
      const bx=(1-et)*(1-et)*o.x+2*(1-et)*et*(cx-f.x)+et*et*0;
      const by=(1-et)*(1-et)*o.y+2*(1-et)*et*(cy-f.y)+et*et*0;
      el.setAttribute('opacity',Math.min(1,t*3));
      el.setAttribute('transform',`translate(${bx},${by}) scale(${.05+.95*et})`);
    },
    onD(){
      el.removeAttribute('transform');el.setAttribute('opacity',1);flash(fl);
      if(i===0){fadeIn(document.getElementById('halo-b'),600,0);fadeIn(document.getElementById('halo-b2'),600,0);}
      if(i===6){fadeIn(document.getElementById('halo-r'),600,0);fadeIn(document.getElementById('halo-r2'),600,0);}
    }});
});
['l1','l2','l3','l4','l5','l6','l7','l8'].forEach((id,li)=>{
  const el=document.getElementById(id),delay=LS+li*LL;
  if(li===7){anim({dur:LD,delay,onP(t){el.setAttribute('opacity',easeOut(t));}});}
  else{
    const len=Math.hypot(el.x2.baseVal.value-el.x1.baseVal.value,el.y2.baseVal.value-el.y1.baseVal.value);
    el.setAttribute('opacity',1);el.style.strokeDasharray=len;el.style.strokeDashoffset=len;
    anim({dur:LD,delay,onP(t){el.style.strokeDashoffset=len*(1-easeOut(t));}});}
});
